definition.script:
pipeline {
    agent none
    triggers { pollSCM('H/5 * * * *') }
    environment {
        PROJECT_NAME = 'arcana-ios'
        VERSION      = '1.0.0'
        MAC_PATH     = "/opt/homebrew/opt/ruby/bin:/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin"
        SONAR_TOKEN  = credentials('sonarqube-token')
        SONAR_HOST_URL = 'http://sonarqube:9000/sonarqube'
    }
    options {
        timeout(time: 120, unit: 'MINUTES')
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }
    stages {
        stage('Checkout') {
            agent { label 'macos' }
            steps {
                withCredentials([usernamePassword(credentialsId: 'github-credentials',
                        usernameVariable: 'GIT_USER', passwordVariable: 'GIT_PASS')]) {
                    sh '''
                        export PATH=${MAC_PATH}
                        if [ -d .git ]; then
                            git fetch --tags --force --progress \
                                "https://${GIT_USER}:${GIT_PASS}@github.com/YOUR_ORG/arcana-ios.git" \
                                +refs/heads/*:refs/remotes/origin/*
                            git checkout -f origin/main
                        else
                            git clone --branch main \
                                "https://${GIT_USER}:${GIT_PASS}@github.com/YOUR_ORG/arcana-ios.git" .
                        fi
                    '''
                }
            }
        }
        stage('Build') {
            agent { label 'macos' }
            steps {
                sh '''
                    export PATH=${MAC_PATH}
                    xcodebuild -project arcana-ios.xcodeproj -scheme arcana-ios \
                        -configuration Release \
                        -destination 'generic/platform=iOS' \
                        CODE_SIGNING_ALLOWED=NO build 2>&1 | tail -5 || true
                '''
            }
        }
        stage('Test + Coverage') {
            agent { label 'macos' }
            steps {
                sh '''
                    export PATH=${MAC_PATH}
                    xcrun simctl boot "iPhone 17" 2>/dev/null || true
                    XCRESULT=/tmp/arcana-ios-tests.xcresult
                    rm -rf "${XCRESULT}"
                    xcodebuild -project arcana-ios.xcodeproj -scheme arcana-ios \
                        -destination 'platform=iOS Simulator,name=iPhone 17' \
                        -enableCodeCoverage YES \
                        -resultBundlePath "${XCRESULT}" \
                        -test-timeouts-enabled YES \
                        -maximum-test-execution-time-allowance 120 \
                        test 2>&1 | tail -20 || true
                    python3 scripts/xcresult_to_sonar_coverage.py "${XCRESULT}" coverage-report.xml \
                        || echo "Coverage conversion failed (non-fatal)"
                    xcrun simctl shutdown all 2>/dev/null || true
                    xcrun simctl delete unavailable 2>/dev/null || true
                '''
                stash includes: 'coverage-report.xml,arcana-ios/Sources/**', name: 'sonar-inputs', allowEmpty: true
            }
        }
        stage('SonarQube Analysis') {
            agent { label 'built-in' }
            steps {
                unstash 'sonar-inputs'
                sh '''
                    sonar-scanner \
                        -Dsonar.projectKey=ios-app \
                        "-Dsonar.projectName=iOS App" \
                        -Dsonar.sources=arcana-ios/Sources \
                        "-Dsonar.exclusions=**/DerivedData/**,**/*.xcassets/**,**/build/**" \
                        "-Dsonar.coverage.exclusions=**/Mocks/**,**/*Mock*.swift" \
                        -Dsonar.coverageReportPaths=coverage-report.xml \
                        -Dsonar.scm.disabled=true
                '''
            }
        }
        stage('Deploy to TestFlight') {
            agent { label 'macos' }
            steps {
                catchError(buildResult: 'SUCCESS', stageResult: 'UNSTABLE') {
                    withCredentials([
                        file(credentialsId: 'asc-api-key', variable: 'ASC_KEY_PATH'),
                        string(credentialsId: 'asc-key-id', variable: 'ASC_KEY_ID'),
                        string(credentialsId: 'asc-issuer-id', variable: 'ASC_ISSUER_ID'),
                        string(credentialsId: 'match-password', variable: 'MATCH_PASSWORD')
                    ]) {
                        sh '''
                            export PATH=${MAC_PATH}
                            export LC_ALL=en_US.UTF-8
                            export LANG=en_US.UTF-8
                            bundle install --quiet
                            bundle exec fastlane beta
                        '''
                    }
                }
            }
            post {
                success {
                    archiveArtifacts artifacts: 'build/*.ipa', allowEmptyArchive: true
                }
            }
        }
    }
    post {
        success { echo "iOS build OK: ${PROJECT_NAME} v${VERSION}" }
        failure { echo "iOS build FAILED: ${PROJECT_NAME}" }
    }
}
